#include <iostream>
#include <thread>
#include <chrono>
using namespace std;

void worker(int id) {
    for (int i = 0; i < 3; i++) {
        cout << "Thread " << id << ": step " << i << endl;
        this_thread::sleep_for(chrono::milliseconds(10));
    }
}

int main() {
    thread t1(worker, 1);
    thread t2(worker, 2);

    t1.join();  // wait for t1
    t2.join();  // wait for t2

    cout << "Both done." << endl;
    return 0;
}

#include <iostream>
#include <thread>
#include <mutex>
#include <vector>
using namespace std;

mutex mtx;
int sharedCounter = 0;

void increment(int times) {
    for (int i = 0; i < times; i++) {
        lock_guard<mutex> lock(mtx);  // locks here, unlocks when lock goes out of scope
        sharedCounter++;
    }
}

int main() {
    const int numThreads = 10;
    const int times = 1000;

    vector<thread> threads;
    for (int i = 0; i < numThreads; i++)
        threads.emplace_back(increment, times);

    for (auto& t : threads) t.join();

    cout << "Expected: " << numThreads * times << endl;
    cout << "Got: " << sharedCounter << endl;
    cout << (sharedCounter == numThreads * times ? "Correct!" : "RACE CONDITION!") << endl;

    return 0;
}

#include <iostream>
#include <thread>
#include <atomic>
#include <vector>
using namespace std;

atomic<int> atomicCounter{0};
int unsafeCounter = 0;

void work(int times) {
    for (int i = 0; i < times; i++) {
        atomicCounter.fetch_add(1);  // atomic — thread safe
        unsafeCounter++;             // NOT atomic — race condition
    }
}

int main() {
    vector<thread> threads;
    for (int i = 0; i < 10; i++)
        threads.emplace_back(work, 1000);
    for (auto& t : threads) t.join();

    cout << "Expected: 10000" << endl;
    cout << "Atomic: " << atomicCounter << endl;
    cout << "Unsafe: " << unsafeCounter << " (probably wrong!)" << endl;

    return 0;
}

#include <iostream>
#include <future>
#include <chrono>
#include <vector>
using namespace std;

long long fibonacci(int n) {
    if (n <= 1) return n;
    return fibonacci(n-1) + fibonacci(n-2);
}

int main() {
    // Run two computations in parallel:
    auto f1 = async(launch::async, fibonacci, 38);
    auto f2 = async(launch::async, fibonacci, 36);

    cout << "Waiting for results..." << endl;

    // Both run concurrently — get() waits for each:
    long long r1 = f1.get();
    long long r2 = f2.get();

    cout << "fib(38) = " << r1 << endl;
    cout << "fib(36) = " << r2 << endl;

    return 0;
}

#include <iostream>
#include <thread>
#include <mutex>
#include <condition_variable>
#include <queue>
using namespace std;

mutex mtx;
condition_variable cv;
queue<int> workQueue;
bool done = false;

void producer() {
    for (int i = 1; i <= 5; i++) {
        {
            lock_guard<mutex> lock(mtx);
            workQueue.push(i);
            cout << "Produced: " << i << endl;
        }
        cv.notify_one();  // wake the consumer
    }
    { lock_guard<mutex> lock(mtx); done = true; }
    cv.notify_one();
}

void consumer() {
    while (true) {
        unique_lock<mutex> lock(mtx);
        cv.wait(lock, []{ return !workQueue.empty() || done; });
        while (!workQueue.empty()) {
            cout << "Consumed: " << workQueue.front() << endl;
            workQueue.pop();
        }
        if (done) break;
    }
}

int main() {
    thread p(producer);
    thread c(consumer);
    p.join(); c.join();
    return 0;
}
